function _grantRole(
    uint64 roleId,
    address account,
    uint32 grantDelay,
    uint32 executionDelay
) internal virtual returns (bool) {
    AccessManagerStorage storage $ = _getAccessManagerStorage();
    if (roleId == PUBLIC_ROLE) {
        revert AccessManagerLockedRole(roleId);
    }

    bool newMember = $._roles[roleId].members[account].since == 0;
    uint48 since;

    if (newMember) {
        since = Time.timestamp() + grantDelay;
        $._roles[roleId].members[account] = Access({since: since, delay: executionDelay.toDelay()});
    } else {
        // No setback here. Value can be reset by doing revoke + grant, effectively allowing the admin to perform
        // any change to the execution delay within the duration of the role admin delay.
        ($._roles[roleId].members[account].delay, since) = $._roles[roleId].members[account].delay.withUpdate(
            executionDelay,
            0
        );
    }

    emit RoleGranted(roleId, account, executionDelay, since, newMember);
    return newMember;
}

function _executeOperations(
    uint256 proposalId,
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    bytes32 /* descriptionHash */
) internal virtual override {
    GovernorTimelockAccessStorage storage $ = _getGovernorTimelockAccessStorage();
    uint48 etaSeconds = SafeCast.toUint48(proposalEta(proposalId));
    if (block.timestamp < etaSeconds) {
        revert GovernorUnmetDelay(proposalId, etaSeconds);
    }

    ExecutionPlan storage plan = $._executionPlan[proposalId];

    for (uint256 i = 0; i < targets.length; ++i) {
        (bool controlled, bool withDelay, uint32 nonce) = _getManagerData(plan, i);
        if (controlled) {
            uint32 executedNonce = $._manager.execute{value: values[i]}(targets[i], calldatas[i]);
            if (withDelay && executedNonce != nonce) {
                revert GovernorMismatchedNonce(proposalId, nonce, executedNonce);
            }
        } else {
            (bool success, bytes memory returndata) = targets[i].call{value: values[i]}(calldatas[i]);
            Address.verifyCallResult(success, returndata);
        }
    }
}

function _mintConsecutive(address to, uint96 batchSize) internal virtual returns (uint96) {
    ERC721ConsecutiveStorage storage $ = _getERC721ConsecutiveStorage();
    uint96 next = _nextConsecutiveId();

    // minting a batch of size 0 is a no-op
    if (batchSize > 0) {
        if (address(this).code.length > 0) {
            revert ERC721ForbiddenBatchMint();
        }
        if (to == address(0)) {
            revert ERC721InvalidReceiver(address(0));
        }

        uint256 maxBatchSize = _maxBatchSize();
        if (batchSize > maxBatchSize) {
            revert ERC721ExceededMaxBatchMint(batchSize, maxBatchSize);
        }

        // push an ownership checkpoint & emit event
        uint96 last = next + batchSize - 1;
        $._sequentialOwnership.push(last, uint160(to));

        // The invariant required by this function is preserved because the new sequentialOwnership checkpoint
        // is attributing ownership of `batchSize` new tokens to account `to`.
        _increaseBalance(to, batchSize);

        emit ConsecutiveTransfer(next, last, address(0), to);
    }

    return next;
}

function propose(
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    string memory description
) public virtual override returns (uint256) {
    uint256 proposalId = super.propose(targets, values, calldatas, description);

    uint32 neededDelay = baseDelaySeconds();

    ExecutionPlan storage plan = _executionPlan[proposalId];
    plan.length = SafeCast.toUint16(targets.length);

    for (uint256 i = 0; i < targets.length; ++i) {
        if (calldatas[i].length < 4) {
            continue;
        }
        address target = targets[i];
        bytes4 selector = bytes4(calldatas[i]);
        (bool immediate, uint32 delay) = AuthorityUtils.canCallWithDelay(
            address(_manager),
            address(this),
            target,
            selector
        );
        if ((immediate || delay > 0) && !isAccessManagerIgnored(target, selector)) {
            _setManagerData(plan, i, !immediate, 0);
            // downcast is safe because both arguments are uint32
            neededDelay = uint32(Math.max(delay, neededDelay));
        }
    }

    plan.delay = neededDelay;

    return proposalId;
}

function execute(
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    bytes32 descriptionHash
) public payable virtual returns (uint256) {
    uint256 proposalId = getProposalId(targets, values, calldatas, descriptionHash);

    _validateStateBitmap(
        proposalId,
        _encodeStateBitmap(ProposalState.Succeeded) | _encodeStateBitmap(ProposalState.Queued)
    );

    // mark as executed before calls to avoid reentrancy
    _proposals[proposalId].executed = true;

    // before execute: register governance call in queue.
    if (_executor() != address(this)) {
        for (uint256 i = 0; i < targets.length; ++i) {
            if (targets[i] == address(this)) {
                _governanceCall.pushBack(keccak256(calldatas[i]));
            }
        }
    }

    _executeOperations(proposalId, targets, values, calldatas, descriptionHash);

    // after execute: cleanup governance call queue.
    if (_executor() != address(this) && !_governanceCall.empty()) {
        _governanceCall.clear();
    }

    emit ProposalExecuted(proposalId);

    return proposalId;
}

function _approveTransfer(address from, address to, uint256[] memory tokenIds, uint256[] memory amounts) internal {
    // Do not need to approve mints
    if (from == address(0)) return;

    address extension = _tokensExtension[tokenIds[0]];

    for (uint256 i; i < tokenIds.length;) {
        require(_tokensExtension[tokenIds[i]] == extension, "Mismatched token originators");
        unchecked {
            ++i;
        }
    }
    if (extension != address(0) && _extensionApproveTransfers[extension]) {
        require(
            IERC1155CreatorExtensionApproveTransfer(extension).approveTransfer(
                msg.sender, from, to, tokenIds, amounts
            ),
            "Extension approval failure"
        );
    } else if (_approveTransferBase != address(0)) {
        require(
            IERC1155CreatorExtensionApproveTransfer(_approveTransferBase).approveTransfer(
                msg.sender, from, to, tokenIds, amounts
            ),
            "Extension approval failure"
        );
    }
}

// This function can reenter, but it doesn't pose a risk because it always preserves the property that the amount
    // minted at the beginning is always recovered and burned at the end, or else the entire function will revert.
    // slither-disable-next-line reentrancy-no-eth
    function flashLoan(
        IERC3156FlashBorrower receiver,
        address token,
        uint256 value,
        bytes calldata data
    ) public virtual returns (bool) {
        uint256 maxLoan = maxFlashLoan(token);
        if (value > maxLoan) {
            revert ERC3156ExceededMaxLoan(maxLoan);
        }
        uint256 fee = flashFee(token, value);
        _mint(address(receiver), value);
        if (receiver.onFlashLoan(_msgSender(), token, value, fee, data) != RETURN_VALUE) {
            revert ERC3156InvalidReceiver(address(receiver));
        }
        address flashFeeReceiver = _flashFeeReceiver();
        _spendAllowance(address(receiver), address(this), value + fee);
        if (fee == 0 || flashFeeReceiver == address(0)) {
            _burn(address(receiver), value + fee);
        } else {
            _burn(address(receiver), value);
            _transfer(address(receiver), flashFeeReceiver, fee);
        }
        return true;
    }

function _transferCurrencyWithReturnVal(
    address _currency,
    address _from,
    address _to,
    uint256 _amount
) internal returns (bool success) {
    if (_amount == 0) {
        success = true;
        return success;
    }

    if (_currency == CurrencyTransferLib.NATIVE_TOKEN) {
        // solhint-disable avoid-low-level-calls
        // slither-disable-next-line low-level-calls
        (success, ) = _to.call{ value: _amount }("");
    } else {
        (bool success_, bytes memory data_) = _currency.call(
            abi.encodeWithSelector(IERC20.transferFrom.selector, _from, _to, _amount)
        );

        success = success_;
        if (!success || (data_.length > 0 && !abi.decode(data_, (bool)))) {
            success = false;

            require(
                IERC20(_currency).balanceOf(_from) >= _amount &&
                    IERC20(_currency).allowance(_from, address(this)) >= _amount,
                "Not balance or allowance"
            );
        }
    }
}

function collectPrice(MintRequest calldata _req) internal {
    if (_req.price == 0) {
        require(msg.value == 0, "!Value");
        return;
    }

    uint256 platformFeesTw = (_req.price * DEFAULT_FEE_BPS) / MAX_BPS;
    uint256 platformFees = (_req.price * platformFeeBps) / MAX_BPS;

    if (_req.currency == CurrencyTransferLib.NATIVE_TOKEN) {
        require(msg.value == _req.price, "must send total price.");
    } else {
        require(msg.value == 0, "msg value not zero");
    }

    address saleRecipient = _req.primarySaleRecipient == address(0)
        ? primarySaleRecipient
        : _req.primarySaleRecipient;

    CurrencyTransferLib.transferCurrency(_req.currency, _msgSender(), DEFAULT_FEE_RECIPIENT, platformFeesTw);
    CurrencyTransferLib.transferCurrency(_req.currency, _msgSender(), platformFeeRecipient, platformFees);
    CurrencyTransferLib.transferCurrency(
        _req.currency,
        _msgSender(),
        saleRecipient,
        _req.price - platformFees - platformFeesTw
    );
}

function getLesserAndGreater(
  List storage list,
  uint256 value,
  bytes32 lesserKey,
  bytes32 greaterKey
) private view returns (bytes32, bytes32) {
  // Check for one of the following conditions and fail if none are met:
  //   1. The value is less than the current lowest value
  //   2. The value is greater than the current greatest value
  //   3. The value is just greater than the value for `lesserKey`
  //   4. The value is just less than the value for `greaterKey`
  if (lesserKey == bytes32(0) && isValueBetween(list, value, lesserKey, list.list.tail)) {
    return (lesserKey, list.list.tail);
  } else if (
    greaterKey == bytes32(0) && isValueBetween(list, value, list.list.head, greaterKey)
  ) {
    return (list.list.head, greaterKey);
  } else if (
    lesserKey != bytes32(0) &&
    isValueBetween(list, value, lesserKey, list.list.elements[lesserKey].nextKey)
  ) {
    return (lesserKey, list.list.elements[lesserKey].nextKey);
  } else if (
    greaterKey != bytes32(0) &&
    isValueBetween(list, value, list.list.elements[greaterKey].previousKey, greaterKey)
  ) {
    return (list.list.elements[greaterKey].previousKey, greaterKey);
  } else {
    require(false, "get lesser and greater failure");
  }
}

function checkForDoubleSigning(
  address signer,
  uint256 index,
  bytes memory headerA,
  bytes memory headerB
) public view onlyL1 returns (uint256) {
  require(hashHeader(headerA) != hashHeader(headerB), "Block hashes have to be different");
  uint256 blockNumber = getBlockNumberFromHeader(headerA);
  require(
    blockNumber == getBlockNumberFromHeader(headerB),
    "Block headers are from different height"
  );
  require(index < numberValidatorsInSet(blockNumber), "Bad validator index");
  require(
    signer == validatorSignerAddressFromSet(index, blockNumber),
    "Wasn't a signer with given index"
  );
  uint256 mapA = uint256(getVerifiedSealBitmapFromHeader(headerA));
  uint256 mapB = uint256(getVerifiedSealBitmapFromHeader(headerB));
  require(mapA & (1 << index) != 0, "Didn't sign first block");
  require(mapB & (1 << index) != 0, "Didn't sign second block");
  require(
    countSetBits(mapA) >= minQuorumSize(blockNumber),
    "Not enough signers in the first block"
  );
  require(
    countSetBits(mapB) >= minQuorumSize(blockNumber),
    "Not enough signers in the second block"
  );
  return blockNumber;
}

function cancelOrder(OrderSigned memory orderSigned) public {
    bytes32 hash = keccak256(
        abi.encodePacked(
            address(this),
            orderSigned.tokenGet,
            orderSigned.amountGet,
            orderSigned.tokenGive,
            orderSigned.amountGive,
            orderSigned.expires,
            orderSigned.nonce
        )
    );
    require(
        (orders[msg.sender][hash] ||
            ecrecover(
                keccak256(
                    abi.encodePacked("\x19Ethereum Signed Message:\n32", hash)
                ),
                orderSigned.v,
                orderSigned.r,
                orderSigned.s
            ) ==
            msg.sender)
    );
    orderFills[msg.sender][hash] = orderSigned.amountGet;
    emit Cancel(
        orderSigned.tokenGet,
        orderSigned.amountGet,
        orderSigned.tokenGive,
        orderSigned.amountGive,
        orderSigned.expires,
        orderSigned.nonce,
        msg.sender,
        orderSigned.v,
        orderSigned.r,
        orderSigned.s
    );
}

function executeSale(address _nft, uint256 _tokenId) external {
    tokenDetails storage auction = tokenToAuction[_nft][_tokenId];
    require(auction.duration <= block.timestamp, "Deadline did not pass yet");
    require(auction.seller == msg.sender);
    require(auction.isActive);
    auction.isActive = false;
    if (auction.bidAmounts.length == 0) {
        ERC721(_nft).safeTransferFrom(
            address(this),
            auction.seller,
            _tokenId
        );
    } else {
        (bool success, ) = auction.seller.call{value: auction.maxBid}("");
        require(success);
        for (uint256 i = 0; i < auction.users.length; i++) {
            if (auction.users[i] != auction.maxBidUser) {
                (success, ) = auction.users[i].call{
                value: bids[_nft][_tokenId][auction.users[i]]
                }("");
                require(success);
            }
        }
        ERC721(_nft).safeTransferFrom(
            address(this),
            auction.maxBidUser,
            _tokenId
        );
    }
}

function safeBatchTransferFrom(address _from, address _to, uint256[] calldata _ids, uint256[] calldata _values, bytes calldata _data) external {

    require(_to != address(0x0), "cannot send to zero address");
    require(_ids.length == _values.length, "Array length must match");

    // Only supporting a global operator approval allows us to do only 1 check and not to touch storage to handle allowances.
    require(_from == msg.sender || operatorApproval[_from][msg.sender] == true, "Need operator approval for 3rd party transfers.");

    for (uint256 i = 0; i < _ids.length; ++i) {
        // Cache value to local variable to reduce read costs.
        uint256 id = _ids[i];
        uint256 value = _values[i];

        if (isNonFungible(id)) {
            require(nfOwners[id] == _from);
            nfOwners[id] = _to;
        } else {
            balances[id][_from] = balances[id][_from].sub(value);
            balances[id][_to]   = value.add(balances[id][_to]);
        }
    }

    emit TransferBatch(msg.sender, _from, _to, _ids, _values);

    if (_to.isContract()) {
        _doSafeBatchTransferAcceptanceCheck(msg.sender, _from, _to, _ids, _values, _data);
    }
}

function _enableNode(
    bytes memory domain,
    uint256 offset
) internal returns (bytes32 node) {
    uint256 len = domain.readUint8(offset);
    if (len == 0) {
        return bytes32(0);
    }

    bytes32 parentNode = _enableNode(domain, offset + len + 1);
    bytes32 label = domain.keccak(offset + 1, len);
    node = keccak256(abi.encodePacked(parentNode, label));
    address owner = ens.owner(node);
    if (owner == address(0) || owner == previousRegistrar) {
        if (parentNode == bytes32(0)) {
            Root root = Root(ens.owner(bytes32(0)));
            root.setSubnodeOwner(label, address(this));
            ens.setResolver(node, resolver);
        } else {
            ens.setSubnodeRecord(
                parentNode,
                label,
                address(this),
                resolver,
                0
            );
        }
    } else if (owner != address(this)) {
        revert PreconditionNotMet();
    }
    return node;
}

function resolveBatchCallback(
    bytes calldata response,
    bytes calldata extraData
) external view {
    Lookup[] memory lookups = abi.decode(response, (Batch)).lookups;
    (
        bool extended,
        bool multi,
        bytes4 callbackFunction,
        bytes memory extraData_
    ) = abi.decode(extraData, (bool, bool, bytes4, bytes));
    bytes memory answer;
    if (multi) {
        answer = abi.encode(_toResponseArray(lookups, extended));
    } else {
        Lookup memory lu = lookups[0];
        answer = lu.data;
        if ((lu.flags & FLAG_BATCH_ERROR) != 0) {
            assembly {
                revert(add(answer, 32), mload(answer)) // propagate batch gateway errors
            }
        } else if ((lu.flags & FLAG_CALL_ERROR) != 0) {
            _propagateResolverError(answer);
        } else if (answer.length == 0) {
            revert UnsupportedResolverProfile(bytes4(lu.call));
        }
        if (extended) {
            answer = abi.decode(answer, (bytes)); // unwrap resolve()
        }
    }
    ccipRead(
        address(this),
        abi.encodeWithSelector(callbackFunction, answer, extraData_)
    );
}

function addModelSupport(
    uint256 nodeId,
    uint256 modelId,
    uint256 allocatedFucus
) external nodeExists(nodeId) onlyNodeOperator(nodeId) nodeActive(nodeId) validModel(modelId) {
    if (allocatedFucus == 0) {
        revert InvalidFucusAmount();
    }

    if (nodeModelConfigs[nodeId][modelId].isSupported) {
        revert ModelAlreadySupported(nodeId, modelId);
    }

    // Check if node has enough total FUCUs for this allocation
    uint256 currentAllocated = getTotalAllocatedFucusForNode(nodeId);
    if (currentAllocated + allocatedFucus > nodes[nodeId].totalFucus) {
        revert InsufficientFucus(currentAllocated + allocatedFucus, nodes[nodeId].totalFucus);
    }

    nodeModelConfigs[nodeId][modelId] = NodeModelConfig({
        allocatedFucus: allocatedFucus,
        isSupported: true
    });

    modelSupportingNodes[modelId].add(nodeId);
    nodeSupportedModels[nodeId].add(modelId);

    emit ModelSupportAdded(nodeId, modelId, allocatedFucus);
}

function _isMakerAskValid(
    OrderStructs.Maker calldata makerOrder
) private view returns (bool isValid, bytes4 errorSelector) {
    if (makerOrder.quoteType != QuoteType.Ask) {
        return (isValid, QuoteTypeInvalid.selector);
    }

    if (makerOrder.currency != address(0)) {
        if (makerOrder.currency != WETH) {
            return (isValid, CurrencyInvalid.selector);
        }
    }

    if (makerOrder.additionalParameters.length != 32) {
        return (isValid, OrderInvalid.selector);
    }

    if (makerOrder.itemIds.length != 1 || makerOrder.amounts.length != 1 || makerOrder.amounts[0] != 1) {
        return (isValid, OrderInvalid.selector);
    }

    (, bytes4 priceFeedErrorSelector) = _getFloorPriceNoRevert(makerOrder.collection);

    if (priceFeedErrorSelector == bytes4(0)) {
        isValid = true;
    } else {
        errorSelector = priceFeedErrorSelector;
    }
}

function executeStrategyWithTakerBid(
    OrderStructs.Taker calldata takerBid,
    OrderStructs.Maker calldata makerAsk
)
    external
    view
    returns (uint256 price, uint256[] memory itemIds, uint256[] memory amounts, bool isNonceInvalidated)
{
    uint256 itemIdsLength = makerAsk.itemIds.length;

    if (itemIdsLength == 0 || itemIdsLength != makerAsk.amounts.length) {
        revert OrderInvalid();
    }

    uint256 startPrice = abi.decode(makerAsk.additionalParameters, (uint256));

    if (startPrice < makerAsk.price) {
        revert OrderInvalid();
    }

    uint256 startTime = makerAsk.startTime;
    uint256 endTime = makerAsk.endTime;

    price =
        ((endTime - block.timestamp) * startPrice + (block.timestamp - startTime) * makerAsk.price) /
        (endTime - startTime);

    uint256 maxPrice = abi.decode(takerBid.additionalParameters, (uint256));
    if (maxPrice < price) {
        revert BidTooLow();
    }

    isNonceInvalidated = true;

    itemIds = makerAsk.itemIds;
    amounts = makerAsk.amounts;
}

function isMakerOrderValid(
    OrderStructs.Maker calldata makerAsk,
    bytes4 functionSelector
) external pure override returns (bool isValid, bytes4 errorSelector) {
    if (functionSelector != StrategyDutchAuction.executeStrategyWithTakerBid.selector) {
        return (isValid, FunctionSelectorInvalid.selector);
    }

    if (makerAsk.quoteType != QuoteType.Ask) {
        return (isValid, QuoteTypeInvalid.selector);
    }

    uint256 itemIdsLength = makerAsk.itemIds.length;

    if (itemIdsLength == 0 || itemIdsLength != makerAsk.amounts.length) {
        return (isValid, OrderInvalid.selector);
    }

    for (uint256 i; i < itemIdsLength; ) {
        _validateAmountNoRevert(makerAsk.amounts[i], makerAsk.collectionType);
        unchecked {
            ++i;
        }
    }

    uint256 startPrice = abi.decode(makerAsk.additionalParameters, (uint256));

    if (startPrice < makerAsk.price) {
        return (isValid, OrderInvalid.selector);
    }

    isValid = true;
}

function initialize(
    address _l1SharedBridge,
    bytes32 _l2TokenProxyBytecodeHash,
    address _aliasedOwner
) external reinitializer(2) {
    if (_l1SharedBridge == address(0)) {
        revert ZeroAddress();
    }

    if (_l2TokenProxyBytecodeHash == bytes32(0)) {
        revert EmptyBytes32();
    }

    if (_aliasedOwner == address(0)) {
        revert ZeroAddress();
    }

    l1SharedBridge = _l1SharedBridge;

    // The following statement is true only in freshly deployed environments. However,
    // for those environments we do not need to deploy this contract at all.
    // This check is primarily for local testing purposes.
    if (l2TokenProxyBytecodeHash == bytes32(0) && address(l2TokenBeacon) == address(0)) {
        address l2StandardToken = address(new BridgedStandardERC20{salt: bytes32(0)}());
        l2TokenBeacon = new UpgradeableBeacon{salt: bytes32(0)}(l2StandardToken);
        l2TokenProxyBytecodeHash = _l2TokenProxyBytecodeHash;
        l2TokenBeacon.transferOwnership(_aliasedOwner);
    }
}

function finalizeDeposit(
    address _l1Sender,
    address _l2Receiver,
    address _l1Token,
    uint256 _amount,
    bytes calldata _data
) external {
    // Only the L1 bridge counterpart can initiate and finalize the deposit.
    if (
        AddressAliasHelper.undoL1ToL2Alias(msg.sender) != l1Bridge &&
        AddressAliasHelper.undoL1ToL2Alias(msg.sender) != l1SharedBridge
    ) {
        revert InvalidCaller(msg.sender);
    }

    IL2AssetRouter(L2_ASSET_ROUTER_ADDR).finalizeDepositLegacyBridge({
        _l1Sender: _l1Sender,
        _l2Receiver: _l2Receiver,
        _l1Token: _l1Token,
        _amount: _amount,
        _data: _data
    });

    address l2Token = IL2NativeTokenVault(L2_NATIVE_TOKEN_VAULT_ADDR).l2TokenAddress(_l1Token);

    if (l1TokenAddress[l2Token] == address(0)) {
        l1TokenAddress[l2Token] = _l1Token;
    }

    emit FinalizeDeposit(_l1Sender, _l2Receiver, l2Token, _amount);
}

function _ensureAndSaveTokenDeployed(
    bytes32 _assetId,
    address _originToken,
    bytes memory _erc20Data
) internal override returns (address expectedToken) {
    uint256 tokenOriginChainId;
    (expectedToken, tokenOriginChainId) = _calculateExpectedTokenAddress(_originToken, _erc20Data);
    address l1LegacyToken;
    if (address(L2_LEGACY_SHARED_BRIDGE) != address(0)) {
        l1LegacyToken = L2_LEGACY_SHARED_BRIDGE.l1TokenAddress(expectedToken);
    }

    if (l1LegacyToken != address(0)) {
        _ensureAndSaveTokenDeployedInnerLegacyToken({
            _assetId: _assetId,
            _originToken: _originToken,
            _expectedToken: expectedToken,
            _l1LegacyToken: l1LegacyToken
        });
    } else {
        super._ensureAndSaveTokenDeployedInner({
            _tokenOriginChainId: tokenOriginChainId,
            _assetId: _assetId,
            _originToken: _originToken,
            _erc20Data: _erc20Data,
            _expectedToken: expectedToken
        });
    }
}

function createNewChain(
    uint256 _chainId,
    address _chainTypeManager,
    bytes32 _baseTokenAssetId,
    // solhint-disable-next-line no-unused-vars
    uint256 _salt,
    address _admin,
    bytes calldata _initData,
    bytes[] calldata _factoryDeps
) external onlyOwnerOrAdmin nonReentrant whenNotPaused onlyL1 returns (uint256) {
    _validateChainParams({_chainId: _chainId, _assetId: _baseTokenAssetId, _chainTypeManager: _chainTypeManager});

    chainTypeManager[_chainId] = _chainTypeManager;

    baseTokenAssetId[_chainId] = _baseTokenAssetId;
    settlementLayer[_chainId] = block.chainid;

    address chainAddress = IChainTypeManager(_chainTypeManager).createNewChain({
        _chainId: _chainId,
        _baseTokenAssetId: _baseTokenAssetId,
        _admin: _admin,
        _initData: _initData,
        _factoryDeps: _factoryDeps
    });
    _registerNewZKChain(_chainId, chainAddress, true);
    messageRoot.addNewChain(_chainId);

    emit NewChain(_chainId, _chainTypeManager, _admin);
    return _chainId;
}

function beforeAllHook(
    bytes calldata _terms,
    bytes calldata,
    ModeCode _mode,
    bytes calldata,
    bytes32,
    address,
    address
)
    public
    override
    onlyDefaultExecutionMode(_mode)
{
    TermsData memory terms_ = getTermsInfo(_terms);
    require(terms_.amount > 0, "ERC1155MultiOperationIncreaseBalanceEnforcer:zero-expected-change-amount");
    bytes32 hashKey_ = _getHashKey(msg.sender, terms_.token, terms_.recipient, terms_.tokenId);
    uint256 balance_ = IERC1155(terms_.token).balanceOf(terms_.recipient, terms_.tokenId);
    BalanceTracker memory balanceTracker_ = balanceTracker[hashKey_];

    if (balanceTracker_.expectedIncrease == 0) {
        balanceTracker_.balanceBefore = balance_;
        emit TrackedBalance(msg.sender, terms_.recipient, terms_.token, terms_.tokenId, balance_);
    }

    balanceTracker_.expectedIncrease += terms_.amount;
    balanceTracker_.validationRemaining++;

    balanceTracker[hashKey_] = balanceTracker_;

    emit UpdatedExpectedBalance(msg.sender, terms_.recipient, terms_.token, terms_.tokenId, terms_.amount);
}

function afterAllHook(
    bytes calldata _terms,
    bytes calldata,
    ModeCode,
    bytes calldata,
    bytes32,
    address,
    address
)
    public
    override
{
    TermsData memory terms_ = getTermsInfo(_terms);
    bytes32 hashKey_ = _getHashKey(msg.sender, terms_.token, terms_.recipient, terms_.tokenId);

    balanceTracker[hashKey_].validationRemaining--;

    // Only validate on the last afterAllHook if there are multiple enforcers tracking the same recipient/token/tokenId pair
    if (balanceTracker[hashKey_].validationRemaining > 0) return;

    BalanceTracker memory balanceTracker_ = balanceTracker[hashKey_];

    uint256 balance_ = IERC1155(terms_.token).balanceOf(terms_.recipient, terms_.tokenId);

    require(
        balance_ >= balanceTracker_.balanceBefore + balanceTracker_.expectedIncrease,
        "ERC1155MultiOperationIncreaseBalanceEnforcer:insufficient-balance-increase"
    );

    emit ValidatedBalance(msg.sender, terms_.recipient, terms_.token, terms_.tokenId, balanceTracker_.expectedIncrease);

    delete balanceTracker[hashKey_];
}

function getAddressActiveLoanNFTs(address borrower) public view override returns (uint256[] memory) {

    ILendingPlatformView lending = getLendingPlatformView();

    uint256 activeLoans = 0;

    for(uint256 i = 0; true; i++) {
        try lending.borrowersLoans(borrower, i) returns (uint256 currentLoanId) {
            ILendingStructs.LoanInfo memory currentLoan = lending.getLoanById(currentLoanId);
            if (currentLoan.stage == ILendingStructs.LoanStage.Funded) {
                activeLoans++;
            }
        } catch {
            break;
        }
    }

    uint256[] memory activeNFTs = new uint256[](activeLoans);
    uint256 activeIndex = 0;
    for(uint256 i = 0; true; i++) {
        try lending.borrowersLoans(borrower, i) returns (uint256 currentLoanId) {
            ILendingStructs.LoanInfo memory currentLoan = lending.getLoanById(currentLoanId);
            if (currentLoan.stage == ILendingStructs.LoanStage.Funded) {
                activeNFTs[activeIndex] = currentLoan.tokenId;
                activeIndex++;
            }
        } catch {
            break;
        }
    }

    return activeNFTs;
}

function liquidateAccount(uint256 tokenId, address owner) external override {
    onlyRouter();
    notInLiquidation();

    uint256 tokensInStaking;

    if (isAccountPaused(tokenId)) {

        tokensInStaking = pausedMETFI[tokenId];
        totalPausedMETFI -= tokensInStaking;

    } else {

        StakingInfo memory stakingInfo = stakingInfos[tokenId];
        levelSettings[stakingInfo.level].lockedReverseMETFIs -= stakingInfo.reverseMETFIs;
        tokensInStaking = stakingInfo.reverseMETFIs / levelSettings[stakingInfo.level].reverseMETFIsPerFragment;

    }

    uint256 tokensToBurn = tokensInStaking / 10;
    uint256 tokensToUser = tokensInStaking - tokensToBurn;

    IERC20 METFI = IERC20(contractRegistry.getContractAddress(METFI_HASH));
    IBurnControllerV2 burnController = IBurnControllerV2(contractRegistry.getContractAddress(BURN_CONTROLLER_HASH));

    METFI.safeApprove(address(burnController), tokensToBurn);
    burnController.burnWithTransfer(tokensToBurn);

    delete stakingInfos[tokenId];
    delete pausedMETFI[tokenId];
    delete pausedAccounts[tokenId];

    METFI.safeTransfer(owner, tokensToUser);

    emit StakingAccountLiquidated(tokenId, tokensToUser);
}

function _startTrackingToken(TokenType tokenType, address token, bool isReserveToken, string calldata liquidityControllerName) internal {

    if (tokenType == TokenType.RESERVE_TOKEN) {

        for (uint256 x = 0; x < reserveTokens.length; x++) {
            if (reserveTokens[x] == token) return;
        }

        reserveTokens.push(token);
    } else if (tokenType == TokenType.LIQUIDITY_TOKEN) {

        for (uint256 x = 0; x < liquidityTokens.length; x++) {
            if (liquidityTokens[x] == token) return;
        }

        require(contractRegistry.getPriceCalculator(token) != address(0), ErrNoPriceCalc);

        liquidityTokens.push(token);
    } else if (tokenType == TokenType.LP_TOKEN) {

        for (uint256 x = 0; x < lpTokens.length; x++) {
            if (lpTokens[x].baseToken == token) return;
        }

        if (!isReserveToken) {
            require(contractRegistry.getPriceCalculator(token) != address(0), ErrNoPriceCalc);
        }

        lpTokens.push(LPTokenSettings(liquidityControllerName, token, isReserveToken));
    }
}

function deposit(address to, address localToken, uint256 tokenId, uint256 amount, address canceler)
        external
        nonReentrant
        returns (bytes32 id)
    {
        bool isBridged = _isBridgedToken(localToken);
        address originalToken = isBridged ? BridgedERC1155(localToken).originalToken() : localToken;

        string memory tokenURI_;
        try IERC1155MetadataURI(localToken).uri(tokenId) returns (string memory uri) {
            tokenURI_ = uri;
        } catch {}

        ERC1155Deposit memory erc1155Deposit = ERC1155Deposit({
            nonce: _globalDepositNonce,
            from: msg.sender,
            to: to,
            originalToken: originalToken,
            tokenId: tokenId,
            amount: amount,
            tokenURI: tokenURI_,
            canceler: canceler
        });

        id = _generateDepositId(erc1155Deposit);
        unchecked {
            ++_globalDepositNonce;
        }

        IERC1155(localToken).safeTransferFrom(msg.sender, address(this), tokenId, amount, "");
        if (isBridged) {
            BridgedERC1155(localToken).burn(tokenId, amount);
        }

        signalService.sendSignal(id);
        emit DepositMade(id, erc1155Deposit, localToken);
    }
